import { expandNodeFromContext } from '@/lib/ai';
import { parseAIOutput } from '@/lib/validation';
import crypto from 'crypto';

export async function POST(req: Request) {
  try {
    console.log('[API] /api/expand handler hit');

    if (req.method !== 'POST') {
      return Response.json({ success: false, error: 'Method not allowed' }, { status: 405 });
    }

    let body;
    try {
      body = await req.json();
    } catch (parseErr) {
      return Response.json({ success: false, error: 'Invalid JSON request body' }, { status: 400 });
    }

    const { nodeLabel, existingNodes = [], existingEdges = [] } = body;

    if (!nodeLabel || typeof nodeLabel !== 'string') {
      return Response.json({ success: false, error: 'Node label is required' }, { status: 400 });
    }

    console.log(`[API] Invoking AI expansion pipeline for node: ${nodeLabel}`);
    const rawAiOutput = await expandNodeFromContext(nodeLabel, existingNodes, existingEdges);
    console.log('[API] AI expansion completed');

    let parsedGraph;
    try {
      parsedGraph = parseAIOutput(rawAiOutput);
    } catch (valErr) {
      console.warn('[API] AI Validation error resolving to fallback map', valErr);
      parsedGraph = { nodes: [], edges: [] };
    }

    const allowedLabels = new Set([...existingNodes, ...parsedGraph.nodes.map(n => n.label)]);

    const mappedNodes = parsedGraph.nodes.slice(0, 7).map((n, i) => ({ 
      id: `ext_${crypto.randomBytes(8).toString('hex')}`, 
      label: n.label, 
      type: n.type,
      graphId: 'pending'
    }));

    const mappedEdgesRaw = parsedGraph.edges.map((e) => {
      const sourceId = mappedNodes.find(n => n.label === e[0])?.id || `ext_${e[0]}`;
      const targetId = mappedNodes.find(n => n.label === e[2])?.id || `ext_${e[2]}`;
      const stringifiedLabel = e[1].replace(/\s+/g, '_').toLowerCase();

      return {
        id: `ext_${sourceId}_${stringifiedLabel}_${targetId}`,
        source: sourceId,
        target: targetId,
        label: e[1],
        graphId: 'pending'
      };
    }).filter(e => allowedLabels.has(e.source.replace('ext_', '')) || allowedLabels.has(e.target.replace('ext_', '')));

    const edgeSeen = new Set<string>();
    const mappedEdges = mappedEdgesRaw.filter(e => {
        if(edgeSeen.has(e.id)) return false;
        edgeSeen.add(e.id);
        return true;
    });

    return Response.json({
      success: true,
      data: {
        nodes: mappedNodes,
        edges: mappedEdges,
        _debugRaw: process.env.NODE_ENV === 'development' ? rawAiOutput : undefined
      }
    });

  } catch (err: any) {
    console.error('API /api/expand ERROR:', err);
    return Response.json({ 
      success: false, 
      error: err instanceof Error ? err.message : 'Unknown error processing expand request' 
    }, { status: 500 });
  }
}

import { generateGraphFromText } from '@/lib/ai';
import { parseAIOutput } from '@/lib/validation';
import { constructGraph } from '@/lib/graphEngine';
import { prisma } from '@/lib/db';
import crypto from 'crypto';

const rateLimitMap = new Map<string, number[]>();

export async function POST(req: Request) {
  try {
    console.log('[API] /api/graph handler hit');

    if (req.method !== 'POST') {
      return Response.json({ success: false, error: 'Method not allowed' }, { status: 405 });
    }

    // 1. Basic In-Memory Rate Limiting
    const ip = req.headers.get('x-forwarded-for') || 'unknown';
    const now = Date.now();
    const timestamps = rateLimitMap.get(ip) || [];
    const recent = timestamps.filter(t => now - t < 60000); 

    if (recent.length > 8) {
      return Response.json({ success: false, error: 'Too many requests' }, { status: 429 });
    }
    recent.push(now);
    rateLimitMap.set(ip, recent);

    let body;
    try {
      body = await req.json();
    } catch (parseErr) {
      return Response.json({ success: false, error: 'Invalid JSON request body' }, { status: 400 });
    }

    const { text, mode = 'strict' } = body;

    if (!text || typeof text !== 'string' || text.trim().length === 0) {
      return Response.json({ success: false, error: 'Text input is required' }, { status: 400 });
    }
    if (text.length > 10000) {
      return Response.json({ success: false, error: 'Max length exceeded' }, { status: 400 });
    }

    // 2. Generation & Execution
    console.log('[API] Invoking AI generation pipeline');
    const rawAiOutput = await generateGraphFromText(text, mode);
    console.log('[API] AI generation completed');

    const parsedGraph = parseAIOutput(rawAiOutput);
    const cleanGraph = constructGraph(parsedGraph);

    // 3. Fallback Graph / Empty Protection if logic stripped everything
    if (cleanGraph.nodes.length === 0) {
      cleanGraph.nodes = [
        { label: "Extraction Failed", type: "system" },
        { label: "Data Quality Issue", type: "concept" },
        { label: "Input Text", type: "concept" }
      ];
      cleanGraph.edges = [
        ["Extraction Failed", "caused by", "Data Quality Issue"],
        ["Data Quality Issue", "found in", "Input Text"]
      ];
    }

    // 4. Auto-Generate Title from top topological nodes if AI failed to title it well
    let finalTitle = cleanGraph.title;
    if (!finalTitle || finalTitle === 'Generated Graph') {
      const topNodes = [...cleanGraph.nodes].slice(0, 2).map(n => n.label).join(' & ');
      finalTitle = topNodes ? `Architecture: ${topNodes}` : 'Untitled Network';
    }

    // 5. DB Transaction mapping
    console.log('[API] Opening DB Transaction mappings');
    const result = await prisma.$transaction(async (tx: any) => {
      const graph = await tx.graph.create({
        data: { title: finalTitle }
      });

      // Insert Nodes explicitly calculating deterministic UUIDs mapped inside memory
      const nodesData = cleanGraph.nodes.map(n => ({
        id: crypto.createHash('sha256').update(`${graph.id}_${n.label}`).digest('hex').substring(0, 24),
        label: n.label,
        type: n.type,
        graphId: graph.id
      }));

      await tx.node.createMany({
        data: nodesData,
        skipDuplicates: true
      });

      // Deterministic edges guaranteeing DB rejection of duplicates
      const edgesData = cleanGraph.edges.map(e => {
        const sourceLabel = e[0];
        const labelSafe = e[1].toLowerCase().trim().replace(/[^a-z0-9]/g, '-');
        const targetLabel = e[2];

        // Find IDs assigned locally a step prior
        const sId = nodesData.find(n => n.label === sourceLabel)?.id;
        const tId = nodesData.find(n => n.label === targetLabel)?.id;
        if (!sId || !tId) return null;

        const detId = `${sId}-${labelSafe}-${tId}`.substring(0, 30);

        return {
          id: detId,
          source: sId,
          target: tId,
          label: e[1],
          graphId: graph.id
        };
      }).filter(Boolean) as any[];

      await tx.edge.createMany({
        data: edgesData,
        skipDuplicates: true
      });

      console.log('[API] DB Transaction Complete successfully');
      return {
        graphId: graph.id,
        title: graph.title,
        nodes: nodesData,
        edges: edgesData
      };
    });

    // 6. Return Standardized Struct
    return Response.json({
      success: true,
      data: {
        ...result,
        _debugRaw: process.env.NODE_ENV === 'development' ? rawAiOutput : undefined
      }
    });

  } catch (err: any) {
    console.error('API /api/graph ERROR:', err);
    return Response.json({ 
      success: false, 
      error: err instanceof Error ? err.message : "Unknown error processing graph request" 
    }, { status: 500 });
  }
}

import { prisma } from '@/lib/db';

export async function GET(req: Request, { params }: { params: { id: string } }) {
  try {
    const { id } = params;

    const graph = await prisma.graph.findUnique({
      where: { id },
      include: {
        nodes: true,
        edges: true
      }
    });

    if (!graph) return Response.json({ success: false, error: 'Graph not found' }, { status: 404 });

    const nodes = graph.nodes.map((n: any) => ({
      id: n.id,
      label: n.label,
      type: n.type,
      graphId: n.graphId
    }));

    const edges = graph.edges.map((e: any) => ({
      id: e.id,
      source: e.source,
      target: e.target,
      label: e.label,
      graphId: e.graphId
    }));

    return Response.json({
      success: true,
      data: {
        title: graph.title,
        nodes,
        edges
      }
    });

  } catch (err: any) {
    console.error('API /graphs/[id] error:', err);
    return Response.json({ 
      success: false, 
      error: err instanceof Error ? err.message : 'Unknown error reading graph' 
    }, { status: 500 });
  }
}

import { prisma } from '@/lib/db';

export async function GET(req: Request) {
  try {
    const { searchParams } = new URL(req.url);
    const page = parseInt(searchParams.get('page') || '1', 10);
    const pageSize = 12;

    const graphs = await prisma.graph.findMany({
      orderBy: { createdAt: 'desc' },
      skip: (page - 1) * pageSize,
      take: pageSize,
      select: {
        id: true,
        title: true,
        createdAt: true,
        _count: {
          select: { nodes: true, edges: true } 
        }
      }
    });

    const total = await prisma.graph.count();

    return Response.json({
      success: true,
      data: {
        graphs,
        pagination: {
          total,
          page,
          pages: Math.ceil(total / pageSize)
        }
      }
    });
  } catch (err: any) {
    console.error('API /graphs error:', err);
    return Response.json({ 
      success: false, 
      error: err instanceof Error ? err.message : 'Unknown error reading graphs' 
    }, { status: 500 });
  }
}

'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { ArrowLeft, Clock, LayoutTemplate, Activity } from 'lucide-react';
import clsx from 'clsx';
import { useGraphStore } from '@/store/useGraphStore';

interface GraphMeta {
  id: string;
  title: string;
  createdAt: string;
  _count: { nodes: number; edges: number };
}

export default function SavedGraphs() {
  const [graphs, setGraphs] = useState<GraphMeta[]>([]);
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [loading, setLoading] = useState(true);
  const router = useRouter();
  const { setGraph, resetGraph, setLoading: setGraphLoading } = useGraphStore();

  useEffect(() => {
    async function fetchGraphs() {
      setLoading(true);
      try {
        const res = await fetch(`/api/graphs?page=${page}`);
        const raw = await res.text();
        let parsed;
        try {
          parsed = JSON.parse(raw);
        } catch (e) {
          console.error("Invalid JSON response fetching graphs:", raw);
          return;
        }

        if (parsed.success) {
          setGraphs(parsed.data.graphs);
          setTotalPages(parsed.data.pagination.pages);
        }
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    }
    fetchGraphs();
  }, [page]);

  const loadGraph = async (id: string) => {
    resetGraph(); // Clean UI flicker strictly
    setGraphLoading(true);
    router.push('/dashboard');
    try {
      const res = await fetch(`/api/graphs/${id}`);
      const raw = await res.text();
      let parsed;
      try {
        parsed = JSON.parse(raw);
      } catch (e) {
        console.error("Invalid JSON response fetching graph by ID:", raw);
        throw new Error("Server returned invalid response");
      }

      if (parsed.success) {
        setGraph(parsed.data.title, parsed.data.nodes, parsed.data.edges);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setGraphLoading(false);
    }
  };

  return (
    <main className="min-h-screen bg-zinc-950 text-zinc-100 font-sans p-8 md:p-16">
      <div className="max-w-6xl mx-auto space-y-12 relative">
        <div className="absolute inset-x-0 -top-40 -z-10 transform-gpu overflow-hidden blur-3xl sm:-top-80">
          <div className="relative left-[calc(50%-11rem)] aspect-[1155/678] w-[36.125rem] -translate-x-1/2 rotate-[30deg] bg-gradient-to-tr from-emerald-600 to-emerald-900 opacity-20 sm:left-[calc(50%-30rem)] sm:w-[72.1875rem]" />
        </div>

        <header className="flex items-center justify-between border-b border-zinc-800/80 pb-6">
          <div>
            <h1 className="text-4xl font-bold tracking-tight text-white mb-2 font-mono uppercase">Data Vault</h1>
            <p className="text-zinc-500 font-light">Explore previously extracted topological architectures.</p>
          </div>
          <Link href="/dashboard" className="flex items-center text-sm font-medium text-emerald-400 hover:text-emerald-300 transition-colors bg-emerald-500/10 px-4 py-2 rounded-full border border-emerald-500/20 shadow-lg">
            <ArrowLeft className="w-4 h-4 mr-2" /> Back to Dashboard
          </Link>
        </header>

        {loading ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {[1, 2, 3, 4, 5, 6].map(i => (
              <div key={i} className="h-48 rounded-2xl bg-zinc-900/50 animate-pulse border border-zinc-800" />
            ))}
          </div>
        ) : graphs.length === 0 ? (
          <div className="text-center py-20 border border-zinc-800 rounded-3xl bg-zinc-900/20 backdrop-blur">
            <LayoutTemplate className="w-12 h-12 text-zinc-600 mx-auto mb-4" />
            <h3 className="text-xl font-medium text-zinc-300">No Networks Found</h3>
            <p className="text-zinc-500 mt-2">Generate graphs in your dashboard to view them here.</p>
          </div>
        ) : (
          <>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {graphs.map(graph => (
                <div 
                  key={graph.id} 
                  onClick={() => loadGraph(graph.id)}
                  className="group relative cursor-pointer overflow-hidden rounded-2xl bg-zinc-900/60 backdrop-blur border border-zinc-800 p-6 transition-all duration-300 hover:border-emerald-500/50 hover:bg-zinc-800/60 hover:shadow-[0_0_30px_rgba(16,185,129,0.15)] hover:-translate-y-1"
                >
                  <div className="absolute top-0 left-0 w-1 h-full bg-emerald-500/0 group-hover:bg-emerald-500/80 transition-colors" />

                  <h2 className="text-xl font-semibold mb-6 flex-1 pr-4 line-clamp-2 text-zinc-200 group-hover:text-emerald-400 transition-colors leading-snug">
                    {graph.title}
                  </h2>

                  <div className="flex gap-4 text-xs font-mono text-zinc-500 border-t border-zinc-800 pt-4 group-hover:border-zinc-700 transition-colors">
                    <span className="flex items-center"><Activity className="w-3.5 h-3.5 mr-1 text-emerald-500/60" /> {graph._count.nodes} Nodes</span>
                    <span className="flex items-center"><LayoutTemplate className="w-3.5 h-3.5 mr-1 text-blue-500/60" /> {graph._count.edges} Edges</span>
                  </div>

                  <div className="absolute top-6 right-6 text-xs font-mono text-zinc-600 flex items-center">
                    <Clock className="w-3 h-3 mr-1" />
                    {new Date(graph.createdAt).toLocaleDateString()}
                  </div>
                </div>
              ))}
            </div>

            {totalPages > 1 && (
              <div className="flex justify-center items-center gap-4 pt-10">
                <button 
                  disabled={page === 1}
                  onClick={() => setPage(p => p - 1)}
                  className={clsx("px-4 py-2 rounded-lg text-sm font-medium border transition-colors", page === 1 ? "bg-zinc-900/50 text-zinc-600 border-zinc-800 cursor-not-allowed" : "bg-zinc-900 text-zinc-300 border-zinc-700 hover:bg-zinc-800 hover:text-white")}
                >
                  Previous
                </button>
                <span className="text-zinc-500 font-mono text-sm">
                  Page <strong className="text-zinc-300">{page}</strong> of {totalPages}
                </span>
                <button 
                  disabled={page === totalPages}
                  onClick={() => setPage(p => p + 1)}
                  className={clsx("px-4 py-2 rounded-lg text-sm font-medium border transition-colors", page === totalPages ? "bg-zinc-900/50 text-zinc-600 border-zinc-800 cursor-not-allowed" : "bg-zinc-900 text-zinc-300 border-zinc-700 hover:bg-zinc-800 hover:text-white")}
                >
                  Next
                </button>
              </div>
            )}
          </>
        )}
      </div>
    </main>
  );
}

