import { GoogleGenAI } from '@google/genai';
import { promptCache } from './cache';

const ai = new GoogleGenAI({ apiKey: process.env.GEMINI_API_KEY });

async function fetchWithTimeoutAndRetry(prompt: string, isRetry = false): Promise<string> {
  const timeoutMs = 12000;
  try {
    const genPromise = ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    }).then(res => res.text || '');

    const timeoutPromise = new Promise<string>((_, reject) => 
      setTimeout(() => reject(new Error('AI Request Timeout')), timeoutMs)
    );

    const result = await Promise.race([genPromise, timeoutPromise]);

    // Rough JSON parse check strictly for retry mechanics
    let cleaned = result.trim();
    if (cleaned.startsWith('```json')) cleaned = cleaned.replace(/^```json/, '').replace(/```$/, '').trim();
    else if (cleaned.startsWith('```')) cleaned = cleaned.replace(/^```/, '').replace(/```$/, '').trim();
    JSON.parse(cleaned);

    return result;
  } catch (err: any) {
    if (!isRetry) {
      console.warn(`AI generation failed (${err.message}). Retrying once tightly...`);
      return fetchWithTimeoutAndRetry(prompt + "\n\nCRITICAL ERROR LAST ATTEMPT: You MUST return ONLY valid JSON. No conversational text, no markdown. Start strictly with { and end with }.", true);
    }
    throw err;
  }
}

export async function generateGraphFromText(text: string, mode: 'strict' | 'creative' = 'strict'): Promise<string> {
  const isStrict = mode === 'strict';

  const prompt = `[Prompt v2 - Mode: ${isStrict ? 'Strict' : 'Creative'}]
You are an expert systems architect extracting a knowledge graph from text.

Rules:
1. Max 12-15 nodes. Do not exceed this.
2. No duplicate concepts.
3. Node "type" must be strictly one of: 'protocol', 'concept', 'system', 'component'.
4. Avoid vague relationships like "is" or "related to". Use strong verbs like "defines", "uses", "connects", "operates over".
5. Combine redundant edges holding the same semantic meaning.
6. Ensure ALL nodes are connected. No floating nodes.
${isStrict 
? "7. ONLY extract explicit, factual entities clearly stated. Do not hypothesize." 
: "7. Extract explicit entities, but also infer deeper contextual architectures or abstract lateral concepts safely."}

Return ONLY valid JSON in this exact format:
{
  "nodes": [
    { "label": "Concept A", "type": "concept" },
    { "label": "System X", "type": "system" }
  ],
  "edges": [
    ["Concept A", "relationship description", "System X"]
  ]
}
Text to process:
${text}`;

  const cached = promptCache.get(prompt);
  if (cached) return cached;

  const output = await fetchWithTimeoutAndRetry(prompt);
  promptCache.set(prompt, output);
  return output;
}

export async function expandNodeFromContext(nodeLabel: string, existingNodes: string[], existingEdges: string[]): Promise<string> {
  const prompt = `[Prompt v2 - Expansion]
You are a strict data extractor. Expand the knowledge graph by identifying exactly 5-7 NEW tightly related concepts surrounding "${nodeLabel}".
Rules:
1. DO NOT duplicate any nodes currently in the Existing Nodes array.
2. Ensure relationships dynamically connect the new concepts back to "${nodeLabel}" or other existing concepts.
3. Node "type" must be one of: 'protocol', 'concept', 'system', 'component'.

Existing Nodes: ${JSON.stringify(existingNodes)}

Return ONLY valid JSON in this exact format:
{
  "nodes": [
    { "label": "New Concept A", "type": "concept" }
  ],
  "edges": [
    ["${nodeLabel}", "interacts with", "New Concept A"]
  ]
}`;

  const cached = promptCache.get(prompt);
  if (cached) return cached;

  const output = await fetchWithTimeoutAndRetry(prompt);
  promptCache.set(prompt, output);
  return output;
}

import dagre from 'dagre';
import { AppNode, AppEdge } from './types';

export function getLayoutedElements(nodes: any[], edges: any[], direction = 'LR') {
  const dagreGraph = new dagre.graphlib.Graph();
  dagreGraph.setDefaultEdgeLabel(() => ({}));

  // Setup basic rank direction and spacing to strictly prevent overlaps
  dagreGraph.setGraph({ 
    rankdir: direction, 
    nodesep: 80, 
    edgesep: 50, 
    ranksep: 200 
  });

  nodes.forEach((node) => {
    // Estimating node dimensions width/height
    dagreGraph.setNode(node.id, { width: 160, height: 60 });
  });

  edges.forEach((edge) => {
    dagreGraph.setEdge(edge.source, edge.target);
  });

  dagre.layout(dagreGraph);

  // Return the mapped nodes mapped perfectly to positioning matrices avoiding overlaps.
  const layoutedNodes = nodes.map((node) => {
    const nodeWithPosition = dagreGraph.node(node.id);
    return {
      ...node,
      targetPosition: direction === 'LR' ? 'left' : 'top',
      sourcePosition: direction === 'LR' ? 'right' : 'bottom',
      position: {
        x: nodeWithPosition.x - 160 / 2, // Centering
        y: nodeWithPosition.y - 60 / 2,
      },
    };
  });

  return { nodes: layoutedNodes, edges };
}

import { GraphOutput } from './types';

export function parseAIOutput(rawOutput: string): GraphOutput {
  try {
    let cleaned = rawOutput.trim();
    if (cleaned.startsWith('```json')) {
      cleaned = cleaned.replace(/^```json/, '').replace(/```$/, '').trim();
    } else if (cleaned.startsWith('```')) {
      cleaned = cleaned.replace(/^```/, '').replace(/```$/, '').trim();
    }

    // Safety against trailing commas typically found in AI generations
    cleaned = cleaned.replace(/,\s*([\]}])/g, '$1');

    const parsed = JSON.parse(cleaned);

    if (!Array.isArray(parsed.nodes) || !Array.isArray(parsed.edges)) {
      throw new Error('Invalid graph structure: nodes and edges must be arrays');
    }

    // Dedup nodes by label
    const seenNodeLabels = new Set<string>();
    const nodes = parsed.nodes
      .filter((n: any) => typeof n === 'object' && n !== null && typeof n.label === 'string' && typeof n.type === 'string')
      .filter((n: any) => {
        const lowerLabel = n.label.toLowerCase();
        if (seenNodeLabels.has(lowerLabel)) return false;
        seenNodeLabels.add(lowerLabel);
        return true;
      })
      .slice(0, 15); // Enforce max 15 nodes limit

    // Collect allowed labels to drop disconnected edges safely
    const allowedLabels = new Set(nodes.map((n: any) => n.label.toLowerCase()));

    // Dedup edges by exact source-label-target signature
    const seenEdgeSigs = new Set<string>();
    const edges = parsed.edges
      .filter((e: any) => Array.isArray(e) && e.length === 3 && e.every((part: any) => typeof part === 'string'))
      .filter((e: any) => allowedLabels.has(e[0].toLowerCase()) && allowedLabels.has(e[2].toLowerCase()))
      .filter((e: any) => {
        const sig = `${e[0].toLowerCase()}|${e[1].toLowerCase()}|${e[2].toLowerCase()}`;
        if (seenEdgeSigs.has(sig)) return false;
        seenEdgeSigs.add(sig);
        return true;
      });

    return { 
      title: parsed.title && typeof parsed.title === 'string' ? parsed.title : 'Generated Graph',
      nodes, 
      edges 
    };
  } catch (error: any) {
    console.error('[VALIDATION ERROR] Failed to parse AI output:', error.message);
    return {
      title: "Fallback Graph",
      nodes: [
        { label: "Data Quality Issue", type: "system" },
        { label: "Extraction Failed", type: "concept" }
      ],
      edges: [
        ["Data Quality Issue", "caused by", "Extraction Failed"]
      ]
    };
  }
}

import { create } from 'zustand';
import { AppNode, AppEdge } from '@/lib/types';

interface GraphState {
  title: string | null;
  nodes: AppNode[];
  edges: AppEdge[];
  loading: boolean;
  selectedNode: AppNode | null;
  searchQuery: string;
  focusMode: boolean;
  mode: 'strict' | 'creative';
  error: string | null;
  debugMode: boolean;
  debugLogs: string[];

  setGraph: (title: string, nodes: AppNode[], edges: AppEdge[], rawLog?: string) => void;
  resetGraph: () => void;
  setLoading: (loading: boolean) => void;
  setSelectedNode: (node: AppNode | null) => void;
  setSearchQuery: (query: string) => void;
  setFocusMode: (active: boolean) => void;
  setMode: (mode: 'strict' | 'creative') => void;
  setError: (error: string | null) => void;
  toggleDebugMode: () => void;
  expandNode: (nodeLabel: string) => Promise<void>;
}

export const useGraphStore = create<GraphState>((set, get) => ({
  title: null,
  nodes: [],
  edges: [],
  loading: false,
  selectedNode: null,
  searchQuery: '',
  focusMode: false,
  mode: 'strict',
  error: null,
  debugMode: typeof window !== 'undefined' ? localStorage.getItem('kgb_debug') === 'true' : false,
  debugLogs: [],

  setGraph: (title, nodes, edges, rawLog) => set(state => ({ 
    title, nodes, edges, error: null,
    debugLogs: rawLog ? [rawLog] : state.debugLogs 
  })),

  resetGraph: () => set({ 
    title: null, nodes: [], edges: [], 
    selectedNode: null, searchQuery: '', focusMode: false, 
    error: null, debugLogs: [] 
  }),

  setLoading: (loading) => set({ loading }),
  setSelectedNode: (selectedNode) => set({ selectedNode }),
  setSearchQuery: (searchQuery) => set({ searchQuery }),
  setFocusMode: (focusMode) => set({ focusMode }),
  setMode: (mode) => set({ mode }),
  setError: (error) => set({ error }),

  toggleDebugMode: () => {
    const newVal = !get().debugMode;
    if (typeof window !== 'undefined') localStorage.setItem('kgb_debug', String(newVal));
    set({ debugMode: newVal });
  },

  expandNode: async (nodeLabel) => {
    const state = get();
    if (state.loading) return; // Prevent race conditions
    set({ loading: true, error: null });

    try {
      const existingNodes = state.nodes.map(n => n.label);
      const existingEdges = state.edges.map(e => `${e.source}->${e.target}`);

      const res = await fetch('/api/expand', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ nodeLabel, existingNodes, existingEdges }),
      });

      const raw = await res.text();
      let parsed;
      try {
        parsed = JSON.parse(raw);
      } catch (parseErr) {
        console.error("Invalid JSON expanding response:", raw);
        throw new Error("Server returned invalid response (not JSON)");
      }

      if (!parsed.success) throw new Error(parsed.error || 'Failed to expand node');

      const data = parsed.data;
      const existingLabels = new Set(state.nodes.map(n => n.label.toLowerCase()));
      const newNodes = data.nodes.filter((n: AppNode) => !existingLabels.has(n.label.toLowerCase()));

      const existingEdgeIds = new Set(state.edges.map(e => e.id));
      const newEdges = data.edges.filter((e: AppEdge) => !existingEdgeIds.has(e.id));

      set({ 
        nodes: [...state.nodes, ...newNodes],
        edges: [...state.edges, ...newEdges],
        loading: false,
        debugLogs: data._debugRaw ? [...state.debugLogs, `[EXPAND]\n${data._debugRaw}`] : state.debugLogs
      });
    } catch (error: any) {
      set({ error: error.message, loading: false });
    }
  }
}));
